export type UserRole = "admin" | "moderator" | "visitor";
export type UserFull = {
    id: string;
    projectId: string;
    foreignId: string | null;
    role: UserRole;
    email: string | null;
    name: string | null;
    username: string | null;
    avatar: string | null;
    bio: string | null;
    birthdate: Date | null;
    location: {
        type: "Point";
        coordinates: [number, number];
    } | null;
    metadata: Record<string, any>;
    secureMetadata: Record<string, any>;
    reputation: number;
    isVerified: boolean;
    isActive: boolean;
    lastActive: Date;
    createdAt: Date;
    updatedAt: Date;
    deletedAt: Date | null;
};
export type AuthUser = Pick<UserFull, "id" | "projectId" | "foreignId" | "role" | "email" | "name" | "username" | "avatar" | "bio" | "birthdate" | "metadata" | "reputation" | "isVerified" | "isActive" | "lastActive"> & {
    suspensions: {
        reason: string | null;
        startDate: Date;
        endDate: Date | null;
    }[];
};
export type User = Omit<UserFull, "email" | "secureMetadata" | "isVerified" | "isActive" | "lastActive" | "updatedAt" | "deletedAt">;
